// Script Continued Below
// RAJ 2020.02.18  STRY0063547 - Works with 2 UI Actions that Enable and Disable Shared Attachments for Stories STRY0060676 and STRY0063747
// if form action is either Enable Shared Attachments or Disable Shared Attachments, then prompt user before proceding.
function onSubmit() {

	var proceedWithSharedFolderChange = false;

	// RAJ STRY0063547
	// if form action is Disable Shared Attachments, then prompt user before proceding.
	if (g_form.getActionName() == 'tasker_ProcTaskDisableSharedAttachments') {
		// TODO, NEED TO USE MSG RULES FOR MULTILANGUAGE
		proceedWithSharedFolderChange = confirm("Are you sure you want to disable shared attachments? There may be existing shared attachments in the Process. Shared attachments will not be deleted but will be hidden.");

		if (proceedWithSharedFolderChange == false) {
			// the user chose no and does not want to disable sharing of attachments for the entire tree
			// do not submit to server, cancel the submit
			return false;
		}
	}
	// RAJ - 2020-03-27 - STRY0063747
	// if form action is Disable Shared Documents, then prompt user before proceding.
	if (g_form.getActionName() == 'tasker_disableProcessTaskSharedDocuments') {
		// TODO, NEED TO USE MSG RULES FOR MULTILANGUAGE
		proceedWithSharedFolderChange = confirm("Are you sure you want to disable shared documents? There may be existing shared documents in the Process. Shared documents will not be deleted but will be hidden.");
		if (proceedWithSharedFolderChange == false) {
			// the user chose no and does not want to disable sharing of attachments for the entire tree
			// do not submit to server, cancel the submit
			return false;
		}
	}
}
